"use strict";(globalThis.webpackChunkdocusaurus_site=globalThis.webpackChunkdocusaurus_site||[]).push([[98624],{38835(e,t,i){i.r(t),i.d(t,{assets:()=>c,contentTitle:()=>a,default:()=>d,frontMatter:()=>n,metadata:()=>s,toc:()=>h});const s=JSON.parse('{"id":"BoardSpecificNotes/GigE_Vision/S08_Ethernet_switches_routers_IGMP_and_IP_multicast","title":"Ethernet switches, routers, IGMP, and IP multicast","description":"When configuring your GigE Vision camera and Gbit Ethernet network adapter for multicasting, there are a few networking concepts with which you should be familiar. This section provides some background information for the requirements of a network designed to deliver a multicast service.","source":"@site/docs/BoardSpecificNotes/GigE_Vision/S08_Ethernet_switches_routers_IGMP_and_IP_multicast.md","sourceDirName":"BoardSpecificNotes/GigE_Vision","slug":"/BoardSpecificNotes/GigE_Vision/S08_Ethernet_switches_routers_IGMP_and_IP_multicast","permalink":"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/BoardSpecificNotes/GigE_Vision/S08_Ethernet_switches_routers_IGMP_and_IP_multicast","draft":false,"unlisted":false,"tags":[],"version":"current","frontMatter":{"doctype":"BoardSpecificNotes","part":"","chapter":"GigE_Vision","section":"Ethernet_switches_routers_IGMP_and_IP_multicast","module_tag":null,"product":"Aurora-Imaging-Library-board-specific-notes","version":1100,"path":"BoardSpecificNotes /  / gige / Ethernet switches routers IGMP and IP multicast"},"sidebar":"boardSpecificNotesSidebar","previous":{"title":"Using IP multicast","permalink":"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/BoardSpecificNotes/GigE_Vision/S07_IP_multicast"},"next":{"title":"Using a Gbit Ethernet switch with GigE Vision-compliant cameras","permalink":"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/BoardSpecificNotes/GigE_Vision/S09_Using_an_Ethernet_switch_with_GigE_vision_complaint_cameras"}}');var r=i(74848),o=i(28453);const n={doctype:"BoardSpecificNotes",part:"",chapter:"GigE_Vision",section:"Ethernet_switches_routers_IGMP_and_IP_multicast",module_tag:null,product:"Aurora-Imaging-Library-board-specific-notes",version:1100,path:"BoardSpecificNotes /  / gige / Ethernet switches routers IGMP and IP multicast"},a="Ethernet switches, routers, IGMP, and IP multicast",c={},h=[{value:"Internet Group Management Protocol (IGMP)",id:"internet-group-management-protocol-igmp",level:2},{value:"Ethernet switches and multicast",id:"ethernet-switches-and-multicast",level:2},{value:"IGMP snooping and Ethernet switches",id:"igmp-snooping-and-ethernet-switches",level:2},{value:"Using IP multicast without a router",id:"using-ip-multicast-without-a-router",level:2}];function l(e){const t={a:"a",code:"code",em:"em",h1:"h1",h2:"h2",header:"header",li:"li",p:"p",ul:"ul",...(0,o.R)(),...e.components};return(0,r.jsxs)(r.Fragment,{children:[(0,r.jsx)(t.header,{children:(0,r.jsx)(t.h1,{id:"ethernet-switches-routers-igmp-and-ip-multicast",children:"Ethernet switches, routers, IGMP, and IP multicast"})}),"\n",(0,r.jsx)(t.p,{children:"When configuring your GigE Vision camera and Gbit Ethernet network adapter for multicasting, there are a few networking concepts with which you should be familiar. This section provides some background information for the requirements of a network designed to deliver a multicast service."}),"\n",(0,r.jsx)(t.p,{children:"A network designed to deliver a multicast service can include the following hardware components:"}),"\n",(0,r.jsxs)(t.ul,{children:["\n",(0,r.jsx)(t.li,{children:"A multicast transmitter (for example, your GigE Vision camera)."}),"\n",(0,r.jsx)(t.li,{children:"Ethernet routers."}),"\n",(0,r.jsx)(t.li,{children:"Ethernet switches."}),"\n",(0,r.jsx)(t.li,{children:"Host multicast receivers (for example, your Aurora Imaging Library GigE Vision applications with a controller, worker, or monitor multicast digitizer)."}),"\n"]}),"\n",(0,r.jsx)(t.p,{children:"Each component fills a role. To deliver a multicast service, the Internet Group Management Protocol (IGMP) is used your local network."}),"\n",(0,r.jsx)(t.h2,{id:"internet-group-management-protocol-igmp",children:"Internet Group Management Protocol (IGMP)"}),"\n",(0,r.jsx)(t.p,{children:"IGMP is a standard that specifies how a Host can register with a router to receive specific multicast traffic. IGMP operates between the client computer (such as, the computers running your Aurora Imaging Library GigE Vision applications using a controller, worker, or monitor multicast digitizer) and a local multicast router."}),"\n",(0,r.jsxs)(t.p,{children:["An Aurora Imaging Library digitizer allocated with ",(0,r.jsx)(t.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/dig/MdigAlloc",children:(0,r.jsx)(t.code,{children:"M_GC_MULTICAST_CONTROLLER"})}),", ",(0,r.jsx)(t.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/dig/MdigAlloc",children:(0,r.jsx)(t.code,{children:"M_GC_MULTICAST_WORKER"})}),", or ",(0,r.jsx)(t.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/dig/MdigAlloc",children:(0,r.jsx)(t.code,{children:"M_GC_MULTICAST_MONITOR"})})," will automatically send IGMP requests to a network router asking for membership to a multicast group. The network router will then issue periodic membership queries to the registered members of a multicast group. Upon reception of these queries, Aurora Imaging Library will respond with IGMP report messages. IGMP allows a router to correctly forward multicast traffic."]}),"\n",(0,r.jsx)(t.h2,{id:"ethernet-switches-and-multicast",children:"Ethernet switches and multicast"}),"\n",(0,r.jsx)(t.p,{children:"To correctly establish packet forwarding, an Ethernet switch uses and maintains an address table. Each packet that enters an Ethernet switch is added to this table; the incoming packet's source MAC address is put in the address table along with the port from which the packet came. To know on which port to output the packet, the switch will lookup the packet's destination MAC address in the address table. If the address is found, the packet will be output on the appropriate port. If the destination MAC address is not found, the packet is flooded on all ports. Eventually the address table will allow the switch to avoid flooding ports because almost every packet received can be looked up in the table."}),"\n",(0,r.jsx)(t.p,{children:"Unfortunately this mechanism causes Ethernet switches to flood the broadcast domain with multicast traffic. This is because a switch usually learns MAC addresses by looking into the source address field of all the Ethernet packets it receives. A multicast MAC address is never used as source address for a packet. Such addresses do not appear in the MAC address table, and the switch has no method for learning them. This consumes a lot of bandwidth since all multicast packets received on one port of the switch are output to all other ports of the switch."}),"\n",(0,r.jsx)(t.p,{children:"The diagram below illustrates multicast datagrams transmitted over a network. The GigE Vision camera (A) is sending multicast IP data to clients B and C. The router correctly forwards the data to the networks of B and C because of the IGMP messages gathered. While the router correctly forwards the data to the client's networks, because of the IGMP messages gathered, the LAN switches flood the data to all PCs connected to them."}),"\n",(0,r.jsx)(t.p,{children:(0,r.jsx)(t.em,{children:"[Image: BSN_GigE_Multicast_Diagrams.png]"})}),"\n",(0,r.jsx)(t.h2,{id:"igmp-snooping-and-ethernet-switches",children:"IGMP snooping and Ethernet switches"}),"\n",(0,r.jsx)(t.p,{children:"To eliminate the flooding problem discussed previously, some Ethernet switches support IGMP snooping. With IGMP snooping, the switch intercepts IGMP packets and uses the information it gathers to establish appropriate forwarding rules for the multicast traffic."}),"\n",(0,r.jsx)(t.p,{children:(0,r.jsx)(t.em,{children:"[Image: BSN_GigE_Multicast_Diagrams_02.png]"})}),"\n",(0,r.jsx)(t.p,{children:"IGMP snooping is disabled by default in LAN switches. To avoid your Ethernet switch causing issues with IP multicast flooding, you must enable IGMP snooping in your Ethernet switch using the managed (or other) interface of your switch."}),"\n",(0,r.jsx)(t.h2,{id:"using-ip-multicast-without-a-router",children:"Using IP multicast without a router"}),"\n",(0,r.jsx)(t.p,{children:"IGMP operates between a computer and a local router. If your network does not have a multicast router, IGMP will fail since there is no source for IGMP membership queries. Some Ethernet switches support being the source for IGMP membership queries (IGMP querying). If you do not have a multicast router in your network, you must use an Ethernet switch that supports IGMP querying and IGMP snooping (typically, if one is supported, then they both are)."}),"\n",(0,r.jsx)(t.p,{children:"If both IGMP snooping and IGMP querying are supported by your Ethernet switch, IP multicast becomes possible without the need of a router. Make sure both IGMP snooping and IGMP querying are enabled in your switch since these features are typically disabled by default; enable them using the managed (or other) interface of your Ethernet switch. When IGMP querying is enabled, it sends out periodic IGMP queries that trigger IGMP report messages from computers that want to receive multicast traffic. IGMP querying works with IGMP snooping since your Ethernet switch listens to these IGMP queries to establish appropriate forwarding."})]})}function d(e={}){const{wrapper:t}={...(0,o.R)(),...e.components};return t?(0,r.jsx)(t,{...e,children:(0,r.jsx)(l,{...e})}):l(e)}},28453(e,t,i){i.d(t,{R:()=>n,x:()=>a});var s=i(96540);const r={},o=s.createContext(r);function n(e){const t=s.useContext(o);return s.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function a(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(r):e.components||r:n(e.components),s.createElement(o.Provider,{value:t},e.children)}}}]);